#include <bits/stdc++.h>
using namespace std;

const int N=1e4+4;

int n,m,a[N],s1,s2;

int main(){
    scanf("%d%d",&n,&m);
    for(int i=0;i<=n;i++)
        a[i]=2;
    while(m--){
        int tp,l,r;
        scanf("%d%d%d",&tp,&l,&r);
        if(!tp){
            for(int i=l;i<=r;i++)
                s2+=(a[i]==1),s1-=(a[i]==1),a[i]=0;
        }else{
            for(int i=l;i<=r;i++)
                if(!a[i])
                    a[i]=1,s1++;
        }
    }
    printf("%d\n%d",s1,s2);
    return 0;
}
